/* FXER Profile Module — dynamically mounts the original profile UI without reloading the application. */
(function () {
  'use strict';
  if (window.__FXER_PROFILE_MODULE_LOADED__) return;
  window.__FXER_PROFILE_MODULE_LOADED__ = true;

  var mount = document.getElementById('fxProfileMount');
  if (!mount) {
    console.error('FXER profile mount container was not found.');
    return;
  }

  var style = document.getElementById('fxProfileInjectionStyle');
  if (!style) {
    style = document.createElement('style');
    style.id = 'fxProfileInjectionStyle';
    style.textContent = "\n/* ================================================================\n   FXER Profile Injection — integrated profile page inside the profile tab\n   • isolated with iframe srcdoc to preserve all CSS/JS/Firebase without collisions\n   • bottom navigation stays visible and functional\n   ================================================================ */\n#fxProfileTab{color:#7d8fae;cursor:pointer;flex-direction:column;flex:1;justify-content:center;align-items:center;gap:3px;display:flex;position:relative}\n#fxProfileTab img{object-fit:contain;opacity:.7;width:19px;height:19px}\n#fxProfileTab span{font-size:9px}\n#fxProfileTab.a{color:#3e8cff}\n#fxProfileTab.a img{opacity:1}\n#fxProfileTab.a:before{content:\"\";background:#2f84ff;height:3px;position:absolute;top:0;left:12%;right:12%}\n#fxpiOverlay{position:fixed;top:0;left:0;right:0;bottom:calc(50px + env(safe-area-inset-bottom));z-index:99998;background:#070d1b;direction:rtl;font:500 13px/1.35 system-ui,-apple-system,Segoe UI,Tahoma,Arial,sans-serif;overflow:hidden;transform:translate3d(100%,0,0);opacity:0;visibility:hidden;will-change:transform,opacity;transition:transform .34s cubic-bezier(.22,.61,.36,1),opacity .28s ease,visibility 0s linear .34s;pointer-events:none;-webkit-tap-highlight-color:transparent}\n#fxpiOverlay.fxpi-open{transform:translate3d(0,0,0);opacity:1;visibility:visible;transition:transform .38s cubic-bezier(.22,.61,.36,1),opacity .22s ease,visibility 0s linear 0s;pointer-events:auto}\n#fxpiSheet{background:transparent;color:#eef5ff;width:100%;height:100%;max-width:none;max-height:none;border:0;border-radius:0;box-shadow:none;display:flex;flex-direction:column;overflow:hidden;padding:0;margin:0}\n#fxpiHead,#fxpiClose{display:none!important}\n#fxpiBody{flex:1 1 auto;min-height:0;width:100%;height:100%;overflow:hidden;padding:0;margin:0;border:0;-webkit-overflow-scrolling:touch;position:relative;background:#070d1b}\n#fxpiBody .fxpi-loading{color:#7d8fae;text-align:center;padding:20px 0}\n#fxpiBody .fxpi-err{color:#ff8080;text-align:center;padding:14px;margin:14px;background:#2a1a1f;border:1px solid #4d2530;border-radius:8px}\n#fxpiFrame{display:block;width:100%;height:100%;border:0;background:#070d1b}\nbody.fxpi-locked .app{pointer-events:auto}\n@media (prefers-reduced-motion: reduce){#fxpiOverlay{transition:opacity .15s ease,visibility 0s linear .15s;transform:none}#fxpiOverlay.fxpi-open{transition:opacity .15s ease,visibility 0s linear 0s;transform:none}}\n";
    document.head.appendChild(style);
  }

  /* The markup is created only here so the main page stays profile-free. */
  mount.innerHTML = "\n\n<div id=\"fxpiOverlay\" aria-hidden=\"true\">\n  <div id=\"fxpiSheet\" role=\"dialog\" aria-modal=\"true\" aria-labelledby=\"fxpiTitle\">\n    <div id=\"fxpiHead\">\n      <h3 id=\"fxpiTitle\">الملف الشخصي</h3>\n      <button id=\"fxpiClose\" type=\"button\" aria-label=\"إغلاق\">×</button>\n    </div>\n    <div id=\"fxpiBody\"><div class=\"fxpi-loading\">جارٍ التحميل…</div></div>\n  </div>\n</div>\n\n";


(function(){
  'use strict';
  var overlay = document.getElementById('fxpiOverlay');
  var body = document.getElementById('fxpiBody');
  var tabBt = document.getElementById('fxProfileTab');
  if(!overlay || !body || !tabBt) return;
  var isOpen = false, isAnimating = false, loaded = false, frame = null;
  var PROFILE_B64 = '';

  // Exposed only for the existing main-page preloader; the payload remains owned by this module.
  window.__FXER_PROFILE_B64__ = PROFILE_B64;

  function decodeProfileHtml(){
    try {
      var bin = atob(PROFILE_B64), bytes = new Uint8Array(bin.length);
      for (var i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return new TextDecoder('utf-8').decode(bytes);
    } catch (e) {
      console.error('Profile decode failed', e);
      return '';
    }
  }

  function setLoading(){ body.innerHTML = '<div class="fxpi-loading">جارٍ تحميل صفحة البروفايل…</div>'; }
  function setError(msg){ body.innerHTML = '<div class="fxpi-err">'+String(msg||'تعذّر تحميل محتوى البروفايل.')+'</div>'; }

  function ensureFrame(){
    if(frame && frame.isConnected) return frame;
    frame = document.createElement('iframe');
    frame.id = 'fxpiFrame';
    frame.setAttribute('title','الملف الشخصي');
    frame.setAttribute('aria-label','الملف الشخصي');
    frame.setAttribute('referrerpolicy','no-referrer');
    frame.setAttribute('loading','eager');
    frame.setAttribute('allow','clipboard-read; clipboard-write');
    return frame;
  }

  function loadProfile(){
    if (loaded && frame && frame.isConnected) return;
    setLoading();
    var html = decodeProfileHtml();
    if (!html) { setError('فشل فك ملف البروفايل المدمج.'); return; }
    var frm = ensureFrame();
    frm.onload = function(){ loaded = true; };
    frm.onerror = function(){ setError('تعذّر فتح صفحة البروفايل المدمجة.'); };
    frm.srcdoc = html;
    body.innerHTML = '';
    body.appendChild(frm);
  }

  function openOverlay(){
    if (isOpen || isAnimating) return;
    isAnimating = true;
    document.body.classList.add('fxpi-locked');
    overlay.style.visibility = 'visible';
    void overlay.offsetWidth;
    overlay.classList.add('fxpi-open');
    overlay.setAttribute('aria-hidden','false');
    tabBt.classList.add('a');
    var done = function(){
      isAnimating = false;
      isOpen = true;
      overlay.removeEventListener('transitionend', done);
    };
    overlay.addEventListener('transitionend', done);
    setTimeout(done, 500);
    loadProfile();
  }

  function closeOverlay(){
    if (!isOpen || isAnimating) return;
    isAnimating = true;
    overlay.classList.remove('fxpi-open');
    overlay.setAttribute('aria-hidden','true');
    tabBt.classList.remove('a');
    var done = function(){
      isAnimating = false;
      isOpen = false;
      document.body.classList.remove('fxpi-locked');
      overlay.removeEventListener('transitionend', done);
    };
    overlay.addEventListener('transitionend', done);
    setTimeout(done, 500);
  }

  var navBar = document.getElementById('nv');
  if (navBar) {
    navBar.addEventListener('click', function(ev){
      var t = ev.target;
      while (t && t !== navBar && !(t.classList && t.classList.contains('ni'))) t = t.parentNode;
      if (!t || t === navBar) return;
      if (t.id === 'fxProfileTab') return;
      if (isOpen) closeOverlay();
    }, true);
  }

  tabBt.addEventListener('click', function(ev){ ev.preventDefault(); openOverlay(); });
  tabBt.addEventListener('keydown', function(ev){ if(ev.key === 'Enter' || ev.key === ' '){ ev.preventDefault(); openOverlay(); } });
  document.addEventListener('keydown', function(ev){ if(ev.key === 'Escape' && isOpen) closeOverlay(); });
  var closeBt = document.getElementById('fxpiClose');
  if (closeBt) closeBt.addEventListener('click', function(ev){ ev.preventDefault(); closeOverlay(); });

  window.FXProfileInjector = {
    open: openOverlay,
    close: closeOverlay,
    reload: function(){ loaded = false; if(frame){ try{frame.remove();}catch(e){} frame = null; } loadProfile(); },
    isOpen: function(){ return isOpen; }
  };
})();

})();
